using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ───────────────────────── AddItem ─────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _cart.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.AreEqual(2, _cart.Items["SKU-001"].Quantity);
        Assert.AreEqual(9.99m, _cart.Items["SKU-001"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantityIsAccumulated()
    {
        _cart.AddItem("SKU-001", 2, 5.00m);
        _cart.AddItem("SKU-001", 3, 5.00m);

        Assert.AreEqual(5, _cart.Items["SKU-001"].Quantity);
    }

    [TestMethod]
    public void AddItem_MultipleSkus_AllTrackedSeparately()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("B", 2, 20m);

        Assert.AreEqual(2, _cart.Items.Count);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(sku!, 1, 1m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_Throws(int qty)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU", qty, 1m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU", 1, -1m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _cart.AddItem("FREE", 1, 0m);
        Assert.AreEqual(0m, _cart.Items["FREE"].Price);
    }

    // ───────────────────── RemoveItem ──────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", 1, 5m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0, _cart.Items.Count);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFound()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _cart.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void RemoveItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.RemoveItem(sku!));
    }

    [TestMethod]
    public void RemoveItem_OneOfMultiple_OtherItemsRemain()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("B", 1, 20m);
        _cart.RemoveItem("A");

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.IsTrue(_cart.Items.ContainsKey("B"));
    }

    // ─────────────────── CalculateTotal ───────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsQuantityTimesPrice()
    {
        _cart.AddItem("SKU", 3, 10.00m);
        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAll()
    {
        _cart.AddItem("A", 2, 5.00m);  // 10
        _cart.AddItem("B", 1, 7.50m);  //  7.50

        Assert.AreEqual(17.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingItem_ExcludesRemoved()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("B", 1, 20m);
        _cart.RemoveItem("A");

        Assert.AreEqual(20m, _cart.CalculateTotal());
    }

    // ──────────────────── ApplyCoupon ─────────────────────

    [TestMethod]
    [DataRow("SAVE10", 0.10)]
    [DataRow("SAVE20", 0.20)]
    [DataRow("HALF",   0.50)]
    public void ApplyCoupon_ValidCode_DiscountsTotalCorrectly(string code, double discountPct)
    {
        _cart.AddItem("SKU", 1, 100.00m);
        _cart.ApplyCoupon(code);

        var expected = 100.00m - 100.00m * (decimal)discountPct;
        Assert.AreEqual(expected, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void ApplyCoupon_NullOrWhitespace_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_ReplacedBySecondCoupon_UsesLatest()
    {
        _cart.AddItem("SKU", 1, 100m);
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("HALF");
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ─────────────── Integration / Workflow ───────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal()
    {
        _cart.AddItem("WIDGET", 4, 25.00m); // 100
        _cart.AddItem("GIZMO",  2, 15.00m); //  30
        _cart.RemoveItem("GIZMO");           // -30
        _cart.ApplyCoupon("SAVE20");         // 20% off

        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }
}

