 using Microsoft.VisualStudio.TestTools.UnitTesting;
 using Store;

 namespace Store.Tests;

 [TestClass]
 public class ShoppingCartTests
 {
     private ShoppingCart _cart = null!;

     [TestInitialize]
     public void Setup() => _cart = new ShoppingCart();

     // ───────────────────────── AddItem ─────────────────────────

     [TestMethod]
     public void AddItem_SingleItem_AppearsInCart()
     {
         _cart.AddItem("SKU-001", 2, 9.99m);

         Assert.AreEqual(1, _cart.Items.Count);
         Assert.AreEqual(2, _cart.Items["SKU-001"].Quantity);
         Assert.AreEqual(9.99m, _cart.Items["SKU-001"].Price);
     }

     [TestMethod]
     public void AddItem_SameSkuTwice_QuantityIsAccumulated()
     {
         _cart.AddItem("SKU-001", 2, 5.00m);
         _cart.AddItem("SKU-001", 3, 5.00m);

         Assert.AreEqual(5, _cart.Items["SKU-001"].Quantity);
     }

     [TestMethod]
     public void AddItem_MultipleSkus_AllTrackedSeparately()
     {
         _cart.AddItem("A", 1, 10m);
         _cart.AddItem("B", 2, 20m);

         Assert.AreEqual(2, _cart.Items.Count);
     }

     [TestMethod]
     [DataRow(null)]
